// Some portions generated by Co-Pilot
import React from "react";
import { render, fireEvent, act } from "@testing-library/react";
import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import Testimonials from "../index";

describe("Testimonials", () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it("renders testimonials of type member", () => {
    const { container } = render(<Testimonials type="member" />);
    expect(container).toBeTruthy();
    // Should render something (members exist in data)
    expect(container.firstChild).not.toBeNull();
  });

  it("renders testimonials of type sustainer", () => {
    const { container } = render(<Testimonials type="sustainer" />);
    // Sustainers may or may not exist in data
    expect(container).toBeTruthy();
  });

  it("renders navigation buttons (prev/next)", () => {
    const { getAllByLabelText } = render(<Testimonials type="member" />);
    expect(getAllByLabelText("Previous Testimonial").length).toBeGreaterThan(0);
    expect(getAllByLabelText("Next Testimonial").length).toBeGreaterThan(0);
  });

  it("navigates to next testimonial when Next button is clicked", () => {
    const { getAllByLabelText } = render(<Testimonials type="member" />);
    const nextButton = getAllByLabelText("Next Testimonial")[0];
    fireEvent.click(nextButton);
    // Should not throw and component should still be there
    expect(nextButton).toBeTruthy();
  });

  it("navigates to previous testimonial when Prev button is clicked", () => {
    const { getAllByLabelText } = render(<Testimonials type="member" />);
    const prevButton = getAllByLabelText("Previous Testimonial")[0];
    fireEvent.click(prevButton);
    expect(prevButton).toBeTruthy();
  });

  it("auto-advances testimonials after 8 seconds", () => {
    const { container } = render(<Testimonials type="member" />);
    // Advance time by 8 seconds
    act(() => {
      vi.advanceTimersByTime(8000);
    });
    expect(container).toBeTruthy();
  });

  it("renders company logo navigation buttons", () => {
    const { container } = render(<Testimonials type="member" />);
    // Should have logo buttons in the navigation section
    const logoButtons = container.querySelectorAll('[aria-label$="Testimonial"]');
    expect(logoButtons.length).toBeGreaterThan(0);
  });

  it("clicking logo button for current testimonial is a no-op", () => {
    const { getAllByLabelText } = render(<Testimonials type="member" />);
    // Get first logo button (should be current)
    const logoButtons = getAllByLabelText(/Testimonial/);
    // Filter to only the company logo buttons (last few ones)
    if (logoButtons.length > 0) {
      // Click the first one (current), shouldn't change state
      fireEvent.click(logoButtons[logoButtons.length - 1]);
      expect(logoButtons[logoButtons.length - 1]).toBeTruthy();
    }
  });

  it("renders dot progress indicators", () => {
    const { container } = render(<Testimonials type="member" />);
    // Should have progress indicator buttons
    const indicators = container.querySelectorAll(".h-2.rounded-full");
    expect(indicators.length).toBeGreaterThan(0);
  });
});
